        return 0;
      }
      const from = new Date(this.leaveForm.fromDate);
      const to = new Date(this.leaveForm.toDate);
      const diff = Math.floor((to.getTime() - from.getTime()) / 86400000);
      return Math.max(diff + 1, 1);
    }
