    get filteredHistoryRequests() {
      const search = this.historySearchTerm.trim().toLowerCase();
      return this.requestHistory.filter(item => {
        const matchesStatus = this.historyStatusFilter === 'all' || item.status === this.historyStatusFilter;
        const matchesSearch = !search || item.requestType.toLowerCase().includes(search) || item.dateTime.toLowerCase().includes(search) || item.reason.toLowerCase().includes(search) || item.status.toLowerCase().includes(search) || item.id.toLowerCase().includes(search);
